window.LEGISLATION=[{"bill":"H R 6644","shortTitle":"21st Century ROAD to Housing Act","policyArea":"Housing and Community Development","sponsor":"Rep. Hill, J. French [R-AR-2]","summaryBullets":["This bill revises federal housing programs, including by expanding available financing for affordable housing and providing grants for planning and community development activities.","It increases the statutory maximum loan limits for FHA mortgage insurance programs for multifamily homes and requires use of a more specific inflation index for such loans.","It increases the maximum eligible income for HUD's HOME Investment Partnerships Program and establishes a grant program to assist regional, state, and local entities with strategies to support affordable housing.","It exempts certain housing-related activities (such as certain construction, improvement, or rehabilitation of residential buildings) from environmental review, and excludes veterans' disability benefits from income counted for Veterans Affairs Supportive Housing (VASH) program eligibility.","It establishes a pilot grant program for public housing agencies (PHAs) and other owners of federally assisted housing to test temperature sensors for compliance, and eliminates the requirement that manufactured homes be built with a permanent chassis.","It authorizes HUD to conduct performance reviews of housing counseling organizations and expands oversight of HUD and PHAs, including requiring PHAs to post contract information on their websites."],"cboCost":null,"latestActionDate":"2026-06-18","latestActionText":"Motion by Senator Thune to refer to Senate Committee on Banking, Housing, and Urban Affairs the House message to accompany H.R. 6644 with instructions to report back forthwith with the following amendment (SA 5825) fell when cloture was invoked on the motion to concur in the House amendment to the Senate amendment to H.R. 6644 in Senate.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/6644"},{"bill":"S J RES 163","shortTitle":"A joint resolution to direct the removal of United States Armed Forces from hostilities within or against the Islamic Republic of Iran that have not been authorized by Congress.","policyArea":"International Affairs","sponsor":"Sen. Merkley, Jeff [D-OR]","summaryBullets":["Directs the President to remove U.S. Armed Forces from hostilities within or against Iran unless a declaration of war or authorization to use military force for such purpose has been enacted.","Specifies that it shall not be construed to prevent the United States from defending against an attack on the United States or its personnel or facilities in other nations."],"cboCost":null,"latestActionDate":"2026-05-13","latestActionText":"Motion to discharge Senate Committee on Foreign Relations rejected by Yea-Nay Vote. 49 - 50. Record Vote Number: 118. (consideration: CR S2250-2255)","congressUrl":"https://www.congress.gov/bill/119th-congress/senate-joint-resolution/163"},{"bill":"S 723","shortTitle":"Tribal Trust Land Homeownership Act of 2025","policyArea":"Native Americans","sponsor":"Sen. Thune, John [R-SD]","summaryBullets":["Sets forth requirements for the Bureau of Indian Affairs (BIA) to process proposed residential leasehold mortgages, business leasehold mortgages, land mortgages, or right-of-way documents, including notifying lenders upon receipt, conducting a preliminary review within 10 days, and approving or disapproving within 20 or 30 days depending on the application type.","Sets requirements for the BIA on response times for completing certified title status reports, notification of processing delays, and the form of notices and delivery of certain reports.","Provides relevant federal agencies and Indian tribes with read-only access to the Trust Asset and Accounting Management System maintained by the BIA.","Requires the Government Accountability Office to report on digitizing documents to streamline and expedite completion of mortgage packages for residential mortgages on Indian land.","Establishes the position of Realty Ombudsman within the BIA's Division of Real Estate Services."],"cboCost":{"title":"S. 723, Tribal Trust Land Homeownership Act of 2025","url":"https://www.cbo.gov/publication/61441"},"latestActionDate":"2026-05-04","latestActionText":"Became Public Law No: 119-88.","congressUrl":"https://www.congress.gov/bill/119th-congress/senate-bill/723"},{"bill":"H R 7147","shortTitle":"Homeland Security and Further Additional Continuing Appropriations Act, 2026","policyArea":"Economics and Public Finance","sponsor":"Rep. Cole, Tom [R-OK-4]","summaryBullets":["Provides continuing FY2026 appropriations to the Department of Homeland Security (DHS) through May 22, 2026, functioning as a continuing resolution (CR) that ends the partial DHS shutdown that began on February 14, 2026, due to a lapse in appropriations.","Generally funds most DHS agencies and programs at FY2025 levels through the earlier of May 22, 2026, or the enactment of the FY2026 DHS appropriations act.","Authorizes back pay, in accordance with current law, for federal employees affected by the partial DHS shutdown.","Ratifies and approves certain obligations incurred during the partial DHS shutdown, including obligations to maintain the essential level of activity to protect life and property and to bring about an orderly termination of government functions."],"cboCost":{"title":"H.R. 7147, Department of Homeland Security Appropriations Act, 2026","url":"https://www.cbo.gov/publication/62028"},"latestActionDate":"2026-04-30","latestActionText":"Became Public Law No: 119-86.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/7147"},{"bill":"H J RES 140","shortTitle":"Providing for congressional disapproval under chapter 8 of title 5, United States Code, of the rule submitted by the Bureau of Land Management relating to Public Land Order No. 7917 for Withdrawal of Federal Lands; Cook, Lake, and Saint Louis Counties, MN.","policyArea":"Public Lands and Natural Resources","sponsor":"Rep. Stauber, Pete [R-MN-8]","summaryBullets":["This joint resolution nullifies Public Land Order 7917, which withdrew approximately 225,504 acres of National Forest System lands in Cook, Lake, and Saint Louis Counties, Minnesota, from mineral and geothermal leasing for 20 years.","In 2023, the Bureau of Land Management issued the order to protect and preserve the Rainy River Watershed, the Boundary Waters Canoe Area Wilderness, the Boundary Waters Canoe Area Wilderness Mining Protection Area, and the 1854 Ceded Territory of the Lake Superior Chippewa from the potential adverse effects of mineral and geothermal exploration and development.","The joint resolution removes such protections and allows the land to be leased for the exploration and development of minerals and geothermal energy."],"cboCost":null,"latestActionDate":"2026-04-27","latestActionText":"Became Public Law No: 119-85.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-joint-resolution/140"},{"bill":"S CON RES 33","shortTitle":"A concurrent resolution setting forth the congressional budget for the United States Government for fiscal year 2026 and setting forth the appropriate budgetary levels for fiscal years 2027 through 2035.","policyArea":"Economics and Public Finance","sponsor":"Sen. Graham, Lindsey [R-SC]","summaryBullets":["Establishes the congressional budget for the federal government for FY2026 and sets budgetary levels for FY2027-FY2035, and provides reconciliation instructions for legislation that increases the deficit.","Recommends levels and amounts for FY2026-FY2035 for federal revenues, new budget authority, budget outlays, deficits, public debt, debt held by the public, and the major functional categories of spending.","Recommends levels for Social Security and Postal Service discretionary administrative expenses for the purpose of budget enforcement in the Senate.","Directs the House Homeland Security, House Judiciary, Senate Homeland Security and Governmental Affairs, and Senate Judiciary Committees to submit recommendations for legislation increasing the deficit over FY2026-FY2035 by not more than $70 billion, due to the Budget Committees by May 15, 2026.","Establishes reserve funds allowing adjustments to committee allocations and budgetary levels to accommodate reconciliation legislation and deficit-neutral legislation supporting the President's immigration enforcement and border security policy changes.","Sets forth budget enforcement procedures addressing budget points of order in the Senate and emergency spending requirements in the House."],"cboCost":null,"latestActionDate":"2026-04-23","latestActionText":"Held at the desk.","congressUrl":"https://www.congress.gov/bill/119th-congress/senate-concurrent-resolution/33"},{"bill":"S 3971","shortTitle":"Small Business Innovation and Economic Security Act","policyArea":"Commerce","sponsor":"Sen. Ernst, Joni [R-IA]","summaryBullets":["Reauthorizes through FY2031 and modifies the Small Business Innovation Research (SBIR) program, the Small Business Technology Transfer (STTR) program, and related pilot programs, which provide competitive federal awards for domestic small businesses to conduct R&D with commercialization potential.","Expands requirements for federal agencies administering these programs to evaluate the security risks of small businesses applying for awards; if an agency denies an application for security reasons, it must give the small business the basis for that determination.","Requires each agency to set a maximum number of proposals per fiscal year that a small business may submit in response to Phase I and Phase II solicitations.","Expands training requirements for agencies' contracting officers and acquisition workforce regarding Phase III (commercialization) awards.","Establishes strategic breakthrough allocations for critical technology areas: additional Phase II SBIR and STTR awards to small businesses that demonstrate effective technology and receive matching funds."],"cboCost":null,"latestActionDate":"2026-04-13","latestActionText":"Became Public Law No: 119-83.","congressUrl":"https://www.congress.gov/bill/119th-congress/senate-bill/3971"},{"bill":"S 1383","shortTitle":"Veterans Accessibility Advisory Committee Act of 2025","policyArea":"Government Operations and Politics","sponsor":"Sen. Scott, Rick [R-FL]","summaryBullets":["Per the latest CRS summary (as passed by the House), the bill's text was changed to the Safeguard American Voter Eligibility Act (SAVE America Act), which requires documentary proof of U.S. citizenship to register to vote and photo identification to vote in federal elections.","Prohibits states from processing a federal voter-registration application unless the applicant presents documentary proof of U.S. citizenship, and specifies acceptable documents (e.g., REAL ID-compliant ID indicating citizenship, a valid U.S. passport, or a government-issued photo ID showing a U.S. birthplace).","Requires states to process applications despite name discrepancies if additional documentation is provided, and to establish an alternative process to demonstrate citizenship.","Requires states to take ongoing steps to ensure only U.S. citizens are registered, including submitting voter lists to the Department of Homeland Security for comparison with the SAVE (Systematic Alien Verification for Entitlements) system, giving flagged individuals a chance to prove citizenship, and removing noncitizens from voter lists.","Provides a private right of action for certain violations and establishes criminal penalties for certain offenses.","Bars officials from providing a federal-election ballot to anyone who does not present valid physical photo ID (with provisional-ballot and religious-objection affidavit procedures), sets photo-ID/Social Security requirements for non-in-person voting with exceptions for overseas military and certain elderly/disabled voters, and requires officials to provide free public access to a digital imaging device to copy photo ID where practicable."],"cboCost":{"title":"S. 1383, Veterans Accessibility Advisory Committee Act of 2025","url":"https://www.cbo.gov/publication/61745"},"latestActionDate":"2026-03-26","latestActionText":"Considered by Senate (Message from the House considered). (consideration: CR S1647)","congressUrl":"https://www.congress.gov/bill/119th-congress/senate-bill/1383"},{"bill":"H R 4294","shortTitle":"MAWS Act of 2026","policyArea":"Public Lands and Natural Resources","sponsor":"Rep. Elfreth, Sarah [D-MD-3]","summaryBullets":["Requires the National Oceanic and Atmospheric Administration (NOAA) to establish a pilot program to facilitate the purchase of blue catfish caught within the Chesapeake Bay Watershed (blue catfish are considered an invasive species in the bay).","Under the program, NOAA must enter into cooperative agreements with manufacturers or processors of pet food, animal feed, or aquaculture feed to purchase blue catfish from watermen and seafood processors.","NOAA must set the minimum price per pound after considering market factors; feedback from watermen, seafood processors, and program participants; and differentiation of price points for fillet and byproduct.","Requires NOAA to enter into a memorandum of understanding with nonfederal partners to develop abundance estimates of blue catfish in the watershed, and to make the first abundance estimate publicly available before beginning the pilot program."],"cboCost":null,"latestActionDate":"2026-03-18","latestActionText":"Received in the Senate and Read twice and referred to the Committee on Commerce, Science, and Transportation.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/4294"},{"bill":"H R 7744","shortTitle":"Department of Homeland Security Appropriations Act, 2026","policyArea":"Economics and Public Finance","sponsor":"Rep. Cole, Tom [R-OK-4]","summaryBullets":["Provides appropriations to the Department of Homeland Security (DHS) for the remainder of FY2026 and ends the partial DHS shutdown that began February 14, 2026, after the continuing resolution funding DHS expired without a regular FY2026 DHS appropriations bill enacted.","Funds Departmental Management, Intelligence, Situational Awareness, and Oversight, including the Office of the Secretary and Executive Management, the Management Directorate, Intelligence/Analysis/Situational Awareness, and the Office of Inspector General.","Funds Security, Enforcement, and Investigations, including Customs and Border Protection, Immigration and Customs Enforcement, the Transportation Security Administration, the Coast Guard, and the Secret Service.","Funds Protection, Preparedness, Response, and Recovery (including CISA and FEMA) and Research, Development, Training, and Services (including USCIS, the Federal Law Enforcement Training Centers, and the Science and Technology Directorate).","Authorizes back pay, under current law, for federal employees affected by the partial DHS shutdown.","Ratifies and approves certain obligations incurred during the partial DHS shutdown, including those to maintain essential activity to protect life and property and to bring about an orderly termination of government functions."],"cboCost":null,"latestActionDate":"2026-03-09","latestActionText":"Received in the Senate and Read twice and referred to the Committee on Appropriations.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/7744"},{"bill":"H R 6472","shortTitle":"Territorial Student Access to Higher Education Act","policyArea":"Education","sponsor":"Del. Moylan, James C. [R-GU-At Large]","summaryBullets":["Requires public institutions of higher education that participate in federal student aid programs to charge no more than in-state tuition and fee rates to students who are residents of Guam, the Northern Mariana Islands, American Samoa, or the U.S. Virgin Islands, provided they are also U.S. nationals."],"cboCost":{"title":"H.R. 6472, Territorial Student Access to Higher Education Act","url":"https://www.cbo.gov/publication/62099"},"latestActionDate":"2026-03-09","latestActionText":"Received in the Senate and Read twice and referred to the Committee on Health, Education, Labor, and Pensions.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/6472"},{"bill":"H CON RES 38","shortTitle":"Directing the President pursuant to section 5(c) of the War Powers Resolution to remove United States Armed Forces from unauthorized hostilities in the Islamic Republic of Iran.","policyArea":"International Affairs","sponsor":"Rep. Massie, Thomas [R-KY-4]","summaryBullets":["Directs the President to terminate the use of U.S. Armed Forces from hostilities against Iran, or any part of the Iranian government or military, unless a declaration of war or an authorization to use military force for such purpose has been enacted.","Specifies that it shall not be construed to prevent the United States from defending itself from imminent attack."],"cboCost":null,"latestActionDate":"2026-03-05","latestActionText":"Motion to reconsider laid on the table Agreed to without objection.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-concurrent-resolution/38"},{"bill":"H RES 1099","shortTitle":"Reaffirming Iran remains the largest state sponsor of terrorism.","policyArea":"International Affairs","sponsor":"Rep. Mast, Brian J. [R-FL-21]","summaryBullets":["States that the House of Representatives declares it is the policy of the United States that Iran continues to be the largest state sponsor of terrorism."],"cboCost":null,"latestActionDate":"2026-03-05","latestActionText":"Motion to reconsider laid on the table Agreed to without objection.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-resolution/1099"},{"bill":"H RES 1100","shortTitle":"Directing the Committee on Ethics to preserve and publicly release records of the Committee's review of violations or alleged violations of clause 9 (as it pertains to acts of sexual harassment) and clause 18 of rule XXIII of the Rules of the House of Representatives.","policyArea":"Congress","sponsor":"Rep. Mace, Nancy [R-SC-1]","summaryBullets":["Directs the House Committee on Ethics to preserve and publicly disclose records related to violations or alleged violations of the Code of Official Conduct (Rule XXIII) involving acts of sexual harassment, unwelcome sexual advance, or sexual assault by a Member, Delegate, or Resident Commissioner.","Requires the committee to preserve all records, including investigative materials, of such a violation or alleged violation.","Requires the committee, within 60 days after the resolution is adopted, to publicly release available reports, conclusions, recommendations, exhibits, and attachments related to such investigations, with the personally identifiable information of victims, alleged victims, and witnesses redacted."],"cboCost":null,"latestActionDate":"2026-03-04","latestActionText":"Motion to reconsider laid on the table Agreed to without objection.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-resolution/1100"},{"bill":"H RES 1095","shortTitle":"Providing for consideration of the bill (H.R. 7744) making appropriations for the Department of Homeland Security for the fiscal year ending September 30, 2026, and for other purposes.","policyArea":"Congress","sponsor":"Rep. Jack, Brian [R-GA-3]","summaryBullets":["Provides for House consideration of H.R. 7744, making appropriations for the Department of Homeland Security for the fiscal year ending September 30, 2026, and for other purposes."],"cboCost":null,"latestActionDate":"2026-03-04","latestActionText":"Motion to reconsider laid on the table Agreed to without objection.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-resolution/1095"},{"bill":"H R 4758","shortTitle":"Homeowner Energy Freedom Act","policyArea":"Energy","sponsor":"Rep. Goldman, Craig A. [R-TX-12]","summaryBullets":["Repeals the Department of Energy's high-efficiency electric home rebate program for certain electrification projects in low- or moderate-income households.","Repeals the Department of Energy's state-based home energy efficiency contractor training grants.","Repeals the Department of Energy's assistance for states and local governments to adopt specified building energy codes.","Rescinds any unobligated balances available for the rebates or for adopting the building energy codes (the unobligated balances for the contractor training grants were previously rescinded by the 2025 reconciliation act)."],"cboCost":{"title":"H.R. 4758, Homeowner Energy Freedom Act","url":"https://www.cbo.gov/publication/62015"},"latestActionDate":"2026-02-25","latestActionText":"Received in the Senate and Read twice and referred to the Committee on Energy and Natural Resources.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/4758"},{"bill":"H R 4626","shortTitle":"Home Appliance Protection and Affordability Act","policyArea":"Energy","sponsor":"Rep. Allen, Rick W. [R-GA-12]","summaryBullets":["Changes how the Department of Energy (DOE) sets or revises energy conservation standards for consumer products such as household appliances, requiring DOE to weigh additional factors tied to product cost and availability.","Lets DOE amend a standard when needed rather than by a fixed deadline, and allows DOE to grant petitions to revoke or amend standards that raise consumer costs, don't significantly conserve energy or water, aren't technologically feasible, or would make a product (e.g., gas stoves) commercially unavailable to all U.S. consumers.","Revises the criteria for prescribing new or amended standards, including new criteria for determining whether a standard is economically justified.","Establishes disclosure requirements for DOE meetings with entities that have ties to China or the Chinese Communist Party, that have studied or advocated for limiting/restricting/banning energy use, or that have applied for or received federal funds.","Prohibits DOE from prescribing new or revised energy conservation standards for distribution transformers.","Allows DOE to prescribe certain new or amended energy and water conservation standards for clothes washers and dishwashers."],"cboCost":{"title":"H.R. 4626, Don't Mess With My Home Appliances Act","url":"https://www.cbo.gov/publication/62096"},"latestActionDate":"2026-02-25","latestActionText":"Received in the Senate and Read twice and referred to the Committee on Energy and Natural Resources.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/4626"},{"bill":"H R 6329","shortTitle":"Information Quality Assurance Act of 2025","policyArea":"Government Operations and Politics","sponsor":"Rep. McClain, Lisa C. [R-MI-9]","summaryBullets":["Requires the Office of Management and Budget (OMB) to revise its guidelines for federal agencies regarding the dissemination or use of 'influential information or evidence.'","Defines influential information or evidence as information an agency can reasonably determine will have a clear and substantial impact on important public actions, policies, or statements, or on important private-sector decisions.","Directs that the guidelines ensure agencies rely on the best reasonably available influential information and evidence appropriate for the purpose when developing, issuing, or informing the public about agency rules and guidance.","Requires agencies to publish the critical factual material relied on in the rulemaking or guidance-development process and a citation to any other source used to inform it.","Requires the guidelines to give the public opportunities to comment on the critical factual material an agency relied upon."],"cboCost":{"title":"H.R. 6329, Information Quality Assurance Act","url":"https://www.cbo.gov/publication/62042"},"latestActionDate":"2026-02-25","latestActionText":"Received in the Senate and Read twice and referred to the Committee on Homeland Security and Governmental Affairs.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/6329"},{"bill":"H RES 1075","shortTitle":"Providing for consideration of the bill (H.R. 4626) ... and providing for consideration of the bill (H.R. 4758) ...","policyArea":"Congress","sponsor":"Rep. Griffith, H. Morgan [R-VA-9]","summaryBullets":["This resolution sets the terms for House floor consideration of H.R. 4626, which would amend the Energy Policy and Conservation Act to bar the Secretary of Energy from prescribing any new or amended energy conservation standard for a product that is not technologically feasible and economically justified.","It also provides for House consideration of H.R. 4758, which would repeal provisions of Public Law 117-169 relating to taxpayer subsidies for home electrification."],"cboCost":null,"latestActionDate":"2026-02-24","latestActionText":"Motion to reconsider laid on the table Agreed to without objection.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-resolution/1075"},{"bill":"S 2503","shortTitle":"ROTOR Act","policyArea":"Transportation and Public Works","sponsor":"Sen. Cruz, Ted [R-TX]","summaryBullets":["Addresses aviation safety by expanding requirements for aircraft tracking and communication using Automatic Dependent Surveillance-Broadcast (ADS-B) technology and increasing oversight.","Generally requires aircraft to operate with ADS-B In equipment so they receive other aircraft's location information and traffic advisories; current law does not require this.","Limits which flights may be treated as 'sensitive government missions' that qualify for an exception from ADS-B Out requirements (e.g., excluding training flights) and adds reporting and notification requirements for that exception.","Requires GAO to review use of the ADS-B Out exception and the DOT Inspector General to annually audit FAA oversight of operations that use it.","Repeals a 2025 law that exempts certain military helicopters from ADS-B Out requirements in the Washington, DC, metropolitan area.","Requires the Army Inspector General to audit the Army's coordination with the FAA, directs the FAA to create an office to coordinate military aircraft airspace use and review flight safety around airports, and requires FAA memoranda of understanding with military agencies for safety information sharing."],"cboCost":null,"latestActionDate":"2026-02-24","latestActionText":"On motion to suspend the rules and pass the bill Failed by the Yeas and Nays: (2/3 required): 264 - 133 (Roll no. 72).","congressUrl":"https://www.congress.gov/bill/119th-congress/senate-bill/2503"},{"bill":"H R 2189","shortTitle":"Law-Enforcement Innovate to De-Escalate Act","policyArea":"Crime and Law Enforcement","sponsor":"Rep. Fitzgerald, Scott [R-WI-5]","summaryBullets":["Removes less-than-lethal projectile devices (e.g., certain TASERs) from regulation under the Gun Control Act.","Defines a 'less-than-lethal projectile device' as one that is not designed or intended to expel (and cannot readily be converted to discharge) commonly used ammunition or projectiles exceeding 500 feet per second.","Requires that such a device also be designed and intended to be used in a manner not likely to cause death or serious bodily injury, and that it not accept (and cannot be readily modified to accept) an ammunition feeding device.","Requires the Bureau of Alcohol, Tobacco, Firearms and Explosives to determine whether a device meets the definition within 90 days of a request."],"cboCost":{"title":"H.R. 2189, Law-Enforcement Innovate to De-Escalate Act","url":"https://www.cbo.gov/publication/62097"},"latestActionDate":"2026-02-24","latestActionText":"Received in the Senate.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/2189"},{"bill":"H J RES 142","shortTitle":"Disapproving the action of the District of Columbia Council in approving the D.C. Income and Franchise Tax Conformity and Revision Temporary Amendment Act of 2025.","policyArea":"Government Operations and Politics","sponsor":"Rep. Gill, Brandon [R-TX-26]","summaryBullets":["This joint resolution nullifies legislation enacted by the Council of the District of Columbia on December 20, 2025, titled the DC Income and Franchise Tax Conformity and Revision Temporary Amendment Act of 2025.","The nullification reinstates certain DC tax code provisions that were in place before the DC legislation, addressing among other things the standard tax deduction, taxation of tipped wages, and depreciation of qualified property.","As background, DC automatically adopts federal tax law changes as DC law (rolling conformity); upon enactment of H.R.1 (the One Big Beautiful Bill Act), its provisions became DC law, including an increased standard deduction, an exemption of tips from taxable income, and an elective 100% depreciation allowance for nonresidential real property.","The DC legislation subsequently decoupled the DC tax code from these and other H.R.1 provisions and amended several other DC tax code provisions, including restoring the DC child tax credit."],"cboCost":null,"latestActionDate":"2026-02-18","latestActionText":"Became Public Law No: 119-78.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-joint-resolution/142"},{"bill":"H R 261","shortTitle":"Undersea Cable Protection Act of 2025","policyArea":"Public Lands and Natural Resources","sponsor":"Rep. Carter, Earl L. \"Buddy\" [R-GA-1]","summaryBullets":["Prohibits the Department of Commerce from enforcing certain permit requirements for activities related to undersea fiber optic cables in national marine sanctuaries.","Specifically bars Commerce from prohibiting or requiring authorization for covered undersea fiber optic cable activities if a license, lease, or permit for that activity has already been issued by a state or federal agency.","Defines covered activities as the installation, continued presence, operation, maintenance, repair, or recovery of undersea fiber optic cables in a national marine sanctuary.","Authorizes Commerce to direct the National Oceanic and Atmospheric Administration (NOAA) to engage in interagency cooperation on federal agency actions likely to destroy, cause loss of, or injure a sanctuary resource and that involve covered activities."],"cboCost":{"title":"H.R. 261, Undersea Cable Protection Act of 2025","url":"https://www.cbo.gov/publication/62090"},"latestActionDate":"2026-02-12","latestActionText":"Received in the Senate and Read twice and referred to the Committee on Commerce, Science, and Transportation.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/261"},{"bill":"H R 3617","shortTitle":"Securing America's Critical Minerals Supply Act","policyArea":"Energy","sponsor":"Rep. James, John [R-MI-10]","summaryBullets":["Requires the Department of Energy (DOE) to secure the supply of 'critical energy resources' essential to U.S. energy security, defined as energy resources essential to the U.S. energy sector and systems whose supply chain is vulnerable to disruption.","Directs DOE to conduct ongoing assessments of resource criticality, U.S. supply chains and their vulnerabilities, supply-chain diversity, capacity constraints on domestic production, and federal regulations affecting domestic production or importation.","Directs DOE to assess how energy security is affected by reliance on imports and how adversarial nations seek to exploit critical energy resource markets to undermine U.S. investment.","Requires DOE to help develop strategies to strengthen critical energy resource supply chains.","Requires DOE to develop substitutes and alternatives to critical energy resources and to improve technology that reuses and recycles them."],"cboCost":{"title":"H.R. 3617, Securing America's Critical Minerals Supply Act","url":"https://www.cbo.gov/publication/61681"},"latestActionDate":"2026-02-12","latestActionText":"Received in the Senate and Read twice and referred to the Committee on Energy and Natural Resources.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/3617"},{"bill":"H RES 1057","shortTitle":"Providing for consideration of the bill (S. 1383) ...; (H.R. 2189) ...; (H.R. 261) ...; and (H.R. 3617) ...; and waiving a requirement of clause 6(a) of rule XIII.","policyArea":"Congress","sponsor":"Rep. Roy, Chip [R-TX-21]","summaryBullets":["This resolution sets the terms for House floor consideration of four measures: S. 1383, to establish the Veterans Advisory Committee on Equal Access.","It provides for consideration of H.R. 2189, to modernize federal firearms laws to account for advancements in technology and less-than-lethal weapons.","It provides for consideration of H.R. 261, to amend the National Marine Sanctuaries Act regarding authorizations for undersea fiber optic cable activities previously authorized by a federal or state agency.","It provides for consideration of H.R. 3617, to amend the Department of Energy Organization Act to secure the supply of critical energy resources, including critical minerals and other materials.","It waives a requirement of clause 6(a) of rule XIII with respect to consideration of certain resolutions reported from the Committee on Rules."],"cboCost":null,"latestActionDate":"2026-02-11","latestActionText":"Motion to reconsider laid on the table Agreed to without objection.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-resolution/1057"},{"bill":"H R 1531","shortTitle":"PROTECT Taiwan Act","policyArea":"International Affairs","sponsor":"Rep. Lucas, Frank D. [R-OK-3]","summaryBullets":["The Pressure Regulatory Organizations To End Chinese Threats to Taiwan Act (PROTECT Taiwan Act) requires certain federal entities to seek to exclude China from six international financial organizations if the President informs Congress that China's actions threaten Taiwan and endanger U.S. interests.","It establishes that it is U.S. policy to seek to exclude Chinese representatives from participating in the activities of these organizations upon such a presidential determination that China's actions pose a threat to Taiwan's security, economic system, or social system, and a danger to U.S. interests.","The six specified organizations are the Group of Twenty, the Bank for International Settlements, the Financial Stability Board, the Basel Committee on Banking Supervision, the International Association of Insurance Supervisors, and the International Organization of Securities Commissions.","If the President so informs Congress, the Department of the Treasury, the Federal Reserve, and the Securities and Exchange Commission must take all necessary steps to advance the exclusion policy.","The President may waive application of this policy to an organization if doing so is in the national interest of the United States."],"cboCost":{"title":"H.R. 1531, Pressure Regulatory Organizations to End Chinese Threats to Taiwan Act","url":"https://www.cbo.gov/publication/61765"},"latestActionDate":"2026-02-11","latestActionText":"Received in the Senate and Read twice and referred to the Committee on Foreign Relations.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/1531"},{"bill":"H RES 1042","shortTitle":"Providing for consideration of the bill (H.R. 2189) ...; (H.R. 261) ...; (H.R. 3617) ...; and for other purposes.","policyArea":"Congress","sponsor":"Rep. Langworthy, Nicholas A. [R-NY-23]","summaryBullets":["This House resolution sets the terms for floor consideration of three bills.","It provides for consideration of H.R. 2189, to modernize federal firearms laws to account for advancements in technology and less-than-lethal weapons.","It provides for consideration of H.R. 261, to amend the National Marine Sanctuaries Act to bar requiring authorization for installing, maintaining, or recovering undersea fiber optic cables in a national marine sanctuary when such activities were previously authorized by a federal or state agency.","It provides for consideration of H.R. 3617, to amend the Department of Energy Organization Act to secure the supply of critical energy resources, including critical minerals and other materials."],"cboCost":null,"latestActionDate":"2026-02-10","latestActionText":"Motion to reconsider laid on the table Agreed to without objection.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-resolution/1042"},{"bill":"H R 4090","shortTitle":"Critical Mineral Dominance Act","policyArea":"Energy","sponsor":"Rep. Stauber, Pete [R-MN-8]","summaryBullets":["This bill directs the Department of the Interior to address mineral supply chain vulnerabilities, including by accelerating and expanding mineral production on federal land (National Forest System land, public lands, and land that may be leased for hardrock mineral activities).","Interior must identify priority mining projects on federal lands that can be immediately approved and take all necessary steps to expedite them.","Interior must identify active, inactive, or proposed projects with the potential to increase production of hardrock minerals or their byproducts, expand existing operations to include such byproducts, or produce hardrock minerals from mine tailings or coal byproducts.","Interior must identify federal land with hardrock mining potential, prioritizing land where a project can most quickly be fully permitted and operational and would most strengthen the domestic mineral supply chain.","Interior must suspend, revise, or rescind agency actions that place undue burdens on mining projects; recommend changes to law to expand U.S. hardrock mineral production; and review state and local laws that impede domestic mining and mineral exploration.","Interior must also report on the dollar value and overall economic impact of U.S. reliance on imports of certain mineral commodities and prioritize efforts to accelerate geologic mapping."],"cboCost":null,"latestActionDate":"2026-02-05","latestActionText":"Received in the Senate and Read twice and referred to the Committee on Energy and Natural Resources.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/4090"},{"bill":"H R 7148","shortTitle":"Consolidated Appropriations Act, 2026","policyArea":"Economics and Public Finance","sponsor":"Rep. Cole, Tom [R-OK-4]","summaryBullets":["This bill provides appropriations to several federal departments and agencies for the remainder of FY2026 and provides continuing FY2026 appropriations for the Department of Homeland Security (DHS) through February 13, 2026; it also extends various expiring programs and authorities.","It includes 5 of the 12 regular FY2026 appropriations bills: the Department of Defense; Labor, Health and Human Services, and Education; Transportation, Housing and Urban Development; Financial Services and General Government; and National Security, Department of State, and Related Programs appropriations acts.","Departments, agencies, and activities funded include Defense, Labor, HHS, Education, Transportation, HUD, the Treasury, the Executive Office of the President, the judiciary, the District of Columbia, the Department of State and related programs, foreign assistance administration and oversight, bilateral economic assistance, international security assistance, multilateral assistance, export and investment assistance, and several related and independent agencies.","It includes a continuing resolution providing continuing FY2026 appropriations to DHS through the earlier of February 13, 2026, or enactment of the DHS appropriations act, funding most DHS programs at FY2025 levels.","It extends numerous expiring programs and authorities, including the U.S. Grain Standards Act, the CFTC whistleblower program, the National Flood Insurance Program, the Agriculture Conservation Experienced Services Program, the TSA Reimbursable Screening Services Program, the Motor Carrier Safety Advisory Committee, several cybersecurity authorities, the technology modernization fund and board, and the U.S. Parole Commission.","It also extends the special assessment on those convicted of certain sexual-abuse or human-trafficking offenses, several immigration-related programs, U.S. Sentencing Commission authority on unmanned-aircraft guidelines, certain bankruptcy fees, trade preferences for Haiti and sub-Saharan Africa, the TANF program, and several health care authorities and programs."],"cboCost":{"title":"H.R. 7148, Consolidated Appropriations Act, 2026","url":"https://www.cbo.gov/publication/62029"},"latestActionDate":"2026-02-03","latestActionText":"Became Public Law No: 119-75.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/7148"},{"bill":"H RES 1032","shortTitle":"Providing for consideration of the Senate amendments to the bill (H.R. 7148) ...; (H.J. Res. 142) ...; and (H.R. 4090) ...","policyArea":"Congress","sponsor":"Rep. Jack, Brian [R-GA-3]","summaryBullets":["This House resolution sets the terms for floor consideration of three measures.","It provides for consideration of the Senate amendments to H.R. 7148, making further consolidated appropriations for the fiscal year ending September 30, 2026.","It provides for consideration of H.J. Res. 142, disapproving the action of the DC Council in approving the D.C. Income and Franchise Tax Conformity and Revision Temporary Amendment Act of 2025.","It provides for consideration of H.R. 4090, to codify certain provisions of certain Executive Orders relating to domestic mining and hardrock mineral resources."],"cboCost":null,"latestActionDate":"2026-02-03","latestActionText":"Motion to reconsider laid on the table Agreed to without objection.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-resolution/1032"},{"bill":"H R 3123","shortTitle":"Ernest Peltz Accrued Veterans Benefits Act","policyArea":"Armed Forces and National Security","sponsor":"Rep. Stefanik, Elise M. [R-NY-21]","summaryBullets":["This bill establishes procedures for the Department of Veterans Affairs (VA) to issue a pension that was due but unpaid at the time of a veteran's death.","If the VA awards entitlement to a pension before the veteran's death but issues payment after the veteran dies, the pension must be paid to the first available recipient among: the veteran's living spouse; the veteran's living children; the veteran's living dependent parents; or the veteran's estate (unless the estate would escheat to the state).","To be eligible, a claimant of accrued benefits must file an application within one year after the veteran's death.","If no application is filed within one year of the veteran's death, the pension must be paid to the veteran's estate unless the estate would escheat."],"cboCost":{"title":"H.R. 3123, Ernest Peltz Accrued Veterans Benefits Act","url":"https://www.cbo.gov/publication/61806"},"latestActionDate":"2026-02-03","latestActionText":"Received in the Senate and Read twice and referred to the Committee on Veterans' Affairs.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/3123"},{"bill":"H R 980","shortTitle":"Veterans Readiness and Employment Improvement Act of 2025","policyArea":"Armed Forces and National Security","sponsor":"Rep. Van Orden, Derrick [R-WI-3]","summaryBullets":["Under the title as introduced (Modernizing the Veterans On-Campus Experience Act of 2025), this bill removes the requirement that educational and vocational counseling services provided by the Department of Veterans Affairs (VA) on campus at institutions of higher learning must be provided by VA counselors."],"cboCost":{"title":"H.R. 980, Veterans Readiness and Employment Improvement Act of 2025","url":"https://www.cbo.gov/publication/61409"},"latestActionDate":"2026-02-03","latestActionText":"Received in the Senate and Read twice and referred to the Committee on Veterans' Affairs.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/980"},{"bill":"H R 6359","shortTitle":"Pregnant Students' Rights Act","policyArea":"Education","sponsor":"Rep. Hinson, Ashley [R-IA-2]","summaryBullets":["Requires each institution of higher education (IHE) that participates in federal student aid programs to provide certain information to prospective and enrolled students about the rights and resources available to pregnant students, or students who may become pregnant while enrolled, who choose to carry a baby to term.","The required information must include a list of community and on-campus resources that help a pregnant student carry the baby to term and care for the baby after birth.","It must include information about accommodations available to help a pregnant student carry the baby to term and parent the baby after birth.","It must include information on how to file a discrimination complaint related to the student's determination to carry a baby to term."],"cboCost":{"title":"H.R. 6359, Pregnant Students' Rights Act","url":"https://www.cbo.gov/publication/62010"},"latestActionDate":"2026-01-26","latestActionText":"Received in the Senate. Read twice. Placed on Senate Legislative Calendar under General Orders. Calendar No. 303.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/6359"},{"bill":"H R 6945","shortTitle":"Supporting Pregnant and Parenting Women and Families Act","policyArea":"Families","sponsor":"Rep. Fischbach, Michelle [R-MN-7]","summaryBullets":["Provides statutory authority for states to use Temporary Assistance for Needy Families (TANF) funds for pregnancy centers.","Applies to pregnancy centers that support protecting the life of the mother and the unborn child.","Applies to pregnancy centers that offer resources and services to mothers, fathers, and families, including relationship counseling, prenatal and pregnancy education, pregnancy testing, diapers, baby clothes, and material supports."],"cboCost":{"title":"H.R. 6945, Supporting Pregnant and Parenting Women and Families Act","url":"https://www.cbo.gov/publication/62087"},"latestActionDate":"2026-01-26","latestActionText":"Received in the Senate and Read twice and referred to the Committee on Finance.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/6945"},{"bill":"H R 5764","shortTitle":"AI for Main Street Act","policyArea":"Commerce","sponsor":"Rep. Alford, Mark [R-MO-4]","summaryBullets":["Requires Small Business Development Centers to assist small businesses in evaluating artificial intelligence.","Includes providing best practices for using artificial intelligence.","Includes providing guidance about using artificial intelligence to plan for unexpected circumstances."],"cboCost":null,"latestActionDate":"2026-01-26","latestActionText":"Received in the Senate and Read twice and referred to the Committee on Small Business and Entrepreneurship.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/5764"},{"bill":"H R 5763","shortTitle":"Main Street Parity Act","policyArea":"Commerce","sponsor":"Rep. Williams, Roger [R-TX-25]","summaryBullets":["Lessens the financing requirements for certain Small Business Administration loans to small businesses for plant acquisition, construction, conversion, or expansion, including the acquisition of land.","Specifically reduces the amount of equity a borrower must provide by 5% of the total cost for loans for limited or single-purpose properties."],"cboCost":null,"latestActionDate":"2026-01-26","latestActionText":"Received in the Senate and Read twice and referred to the Committee on Small Business and Entrepreneurship.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/5763"},{"bill":"H R 2988","shortTitle":"Protecting Prudent Investment of Retirement Savings Act","policyArea":"Labor and Employment","sponsor":"Rep. Allen, Rick W. [R-GA-12]","summaryBullets":["Modifies the requirements for fiduciaries of employer-sponsored retirement plans.","Generally requires a plan fiduciary to make investment decisions based solely on pecuniary factors (factors the fiduciary prudently determines are expected to have a material effect on an investment's risk or return based on appropriate investment horizons consistent with the plan's policies and objectives).","Allows nonpecuniary factors to be considered in certain situations, such as when selecting investment options for certain participant-directed retirement plans or when the fiduciary cannot distinguish between investment alternatives on the basis of pecuniary factors alone.","Prohibits a plan fiduciary from discriminating when selecting, monitoring, and retaining any fiduciary, counsel, employee, or service provider of the plan.","Requires a plan fiduciary to act solely and prudently in the interests of the plan's participants and beneficiaries when exercising a shareholder right (such as voting proxies), while clarifying that this duty does not require voting every proxy or exercising every shareholder right.","Requires a plan fiduciary to provide specified notices for a pension plan that offers participants or beneficiaries the opportunity to select from designated investment alternatives."],"cboCost":{"title":"H.R. 2988, Protecting Prudent Investment of Retirement Savings Act","url":"https://www.cbo.gov/publication/61770"},"latestActionDate":"2026-01-26","latestActionText":"Received in the Senate and Read twice and referred to the Committee on Health, Education, Labor, and Pensions.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/2988"},{"bill":"H CON RES 68","shortTitle":"To direct the removal of United States Armed Forces from Venezuela that have not been authorized by Congress.","policyArea":"International Affairs","sponsor":"Rep. McGovern, James P. [D-MA-2]","summaryBullets":["This concurrent resolution directs the President to remove U.S. Armed Forces from Venezuela.","The removal is required unless a declaration of war has been enacted for that purpose.","The removal is also not required if an authorization to use military force has been enacted for that purpose."],"cboCost":null,"latestActionDate":"2026-01-22","latestActionText":"Motion to reconsider laid on the table Agreed to without objection.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-concurrent-resolution/68"},{"bill":"H RES 1014","shortTitle":"Providing for consideration of the bill (H.R. 7148) ...; (H.R. 7147) ...; and for other purposes.","policyArea":"Congress","sponsor":"Rep. Foxx, Virginia [R-NC-5]","summaryBullets":["This resolution provides for the House consideration of H.R. 7148, a bill making further consolidated appropriations for the fiscal year ending September 30, 2026, and for other purposes.","It also provides for the House consideration of H.R. 7147, a bill making further consolidated appropriations for the fiscal year ending September 30, 2026, and for other purposes.","It addresses other related procedural matters."],"cboCost":null,"latestActionDate":"2026-01-22","latestActionText":"Motion to reconsider laid on the table Agreed to without objection.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-resolution/1014"},{"bill":"H RES 1009","shortTitle":"Providing for consideration of the bill (H.R. 6945) ...; (H.R. 6359) ...; and the joint resolution (H.J. Res. 140) ...","policyArea":"Congress","sponsor":"Rep. Scott, Austin [R-GA-8]","summaryBullets":["Sets forth the rule for House consideration of H.R. 6945, which would amend part A of title IV of the Social Security Act to clarify the authority of states to use funds for pregnancy centers, and for other purposes.","Provides for House consideration of H.R. 6359, which would require institutions of higher education to disseminate information on the rights of, and accommodations and resources for, pregnant students, and for other purposes.","Provides for House consideration of H.J. Res. 140, a joint resolution providing for congressional disapproval of the Bureau of Land Management rule relating to Public Land Order No. 7917 for the withdrawal of federal lands in Cook, Lake, and Saint Louis Counties, Minnesota."],"cboCost":null,"latestActionDate":"2026-01-21","latestActionText":"Motion to reconsider laid on the table Agreed to without objection.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-resolution/1009"},{"bill":"H R 7006","shortTitle":"Financial Services and General Government and National Security, Department of State, and Related Programs Appropriations Act, 2026","policyArea":"Economics and Public Finance","sponsor":"Rep. Cole, Tom [R-OK-4]","summaryBullets":["This bill provides FY2026 appropriations to several federal departments and agencies for activities and programs related to financial services, general government, national security, the administration of foreign affairs, and foreign assistance.","It includes 2 of the 12 regular FY2026 appropriations bills: the Financial Services and General Government Appropriations Act, 2026, and the National Security, Department of State, and Related Programs Appropriations Act, 2026.","Departments, agencies, and activities funded include the Department of the Treasury, the Executive Office of the President, the judiciary, the District of Columbia, the Department of State and related programs, the administration and oversight of foreign assistance programs, bilateral economic assistance, international security assistance, multilateral assistance, export and investment assistance, and several related and independent agencies.","The bill also sets forth requirements and restrictions for using funds provided by this and other appropriations acts."],"cboCost":null,"latestActionDate":"2026-01-15","latestActionText":"Received in the Senate.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/7006"},{"bill":"H R 4593","shortTitle":"SHOWER Act","policyArea":"Energy","sponsor":"Rep. Fry, Russell [R-SC-7]","summaryBullets":["The Saving Homeowners from Overregulation With Exceptional Rinsing Act (SHOWER Act) provides statutory authority for a revised definition of showerhead for the purpose of federal water efficiency regulations.","Specifically, the bill adopts the definition of showerhead established by the American Society of Mechanical Engineers (ASME).","The bill requires the Department of Energy (DOE) to revise existing regulations to reflect the new definition.","Executive Order 14264 (titled Maintaining Acceptable Water Pressure in Showerheads, issued April 9, 2025) directed DOE to rescind its regulatory definition of showerhead; this bill provides statutory authority for a new definition that replaces the rescinded regulations."],"cboCost":{"title":"H.R. 4593, SHOWER Act","url":"https://www.cbo.gov/publication/61973"},"latestActionDate":"2026-01-15","latestActionText":"Received in the Senate and Read twice and referred to the Committee on Energy and Natural Resources.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/4593"},{"bill":"H RES 992","shortTitle":"Providing for consideration of the bill (H.R. 7006) making further consolidated appropriations for the fiscal year ending September 30, 2026, and for other purposes.","policyArea":"Congress","sponsor":"Rep. Foxx, Virginia [R-NC-5]","summaryBullets":["Provides for House consideration of H.R. 7006, a bill making further consolidated appropriations for the fiscal year ending September 30, 2026, and for other purposes."],"cboCost":null,"latestActionDate":"2026-01-14","latestActionText":"Motion to reconsider laid on the table Agreed to without objection.","congressUrl":"https://www.congress.gov/bill/119th-congress/house-resolution/992"},{"bill":"S. 1318","shortTitle":"Fallen Servicemembers Religious Heritage Restoration Act","policyArea":"Armed Forces and National Security","sponsor":"Sen. Moran, Jerry [R-KS]","summaryBullets":["As passed by the House, the bill was rewritten to combine the Foreign Intelligence Accountability Act and the Anti-CBDC Surveillance State Act.","It reauthorizes Title VII of the Foreign Intelligence Surveillance Act (FISA) through April 30, 2029, and expands protections related to Section 702 surveillance of non-U.S. persons abroad.","It adds oversight of FBI queries of U.S. person information, including monthly reviews by the Office of the Director of National Intelligence and referrals of noncompliant queries to the Intelligence Community Inspector General.","It creates criminal penalties for falsifying compliance with querying procedures and for FBI personnel who knowingly violate U.S. person query rules, and limits query approvals to certain FBI attorneys rather than supervisors.","It bars a Federal Reserve bank from offering financial products or accounts directly to individuals or issuing a central bank digital currency (CBDC), and restricts the Federal Reserve Board from using or developing a CBDC, with certain exceptions."],"cboCost":{"title":"S. 1318, Fallen Servicemembers Religious Heritage Restoration Act","url":"https://www.cbo.gov/publication/61727"},"latestActionDate":null,"latestActionText":null,"congressUrl":"https://www.congress.gov/bill/119th-congress/senate-bill/1318"},{"bill":"S. 2","shortTitle":"Secure America Act","policyArea":"Economics and Public Finance","sponsor":"Sen. Graham, Lindsey [R-SC]","summaryBullets":["This bill provides funding to the Department of Homeland Security, U.S. Customs and Border Protection (CBP), and U.S. Immigration and Customs Enforcement (ICE) through FY2029 for immigration enforcement and related activities.","It is a reconciliation bill assembled under the FY2026 budget resolution (S. Con. Res. 33), meaning it moves through expedited procedures that prevent a filibuster and restrict amendments in the Senate.","CBP funding covers personnel; border security, technology, and screening; and immigration enforcement activities.","ICE funding covers personnel, Homeland Security Investigations, enforcement activities, transportation, information technology, facilities and fleet, 287(g) agreements with state and local law enforcement, legal advisers, and certain immigration-related arrests.","It also gives DHS additional funding for immigration enforcement and for state and local participation in homeland security efforts, with the funding generally remaining available through FY2029."],"cboCost":{"title":"Estimated Budgetary Effects of S. 2, the Secure America Act","url":"https://www.cbo.gov/publication/62520"},"latestActionDate":null,"latestActionText":null,"congressUrl":"https://www.congress.gov/bill/119th-congress/senate-bill/2"},{"bill":"H R 556","shortTitle":"Protecting Access for Hunters and Anglers Act","policyArea":"Public Lands and Natural Resources","sponsor":"Rep. Wittman, Robert J. [R-VA-1]","summaryBullets":["This bill bars the Fish and Wildlife Service, the Bureau of Land Management, and the Forest Service from prohibiting or regulating the use of lead ammunition or tackle on federal land or water.","It preserves exceptions for specified existing regulations.","It also allows a restriction where the relevant agency determines, based on field data from that specific unit of federal land or water, that lead ammunition or tackle is the primary cause of a wildlife population decline there, and the state approves the regulation."],"cboCost":{"title":"H.R. 556, Protecting Access for Hunters and Anglers Act","url":"https://www.cbo.gov/publication/62019"},"latestActionDate":null,"latestActionText":null,"congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/556"},{"bill":"H R 1958","shortTitle":"Deporting Fraudsters Act of 2026","policyArea":"Immigration","sponsor":"Rep. Taylor, David [R-OH-2]","summaryBullets":["This bill makes certain public benefits fraud offenses grounds for barring a non-U.S. national from admission into the United States or for deporting them.","It also makes such individuals ineligible for immigration enforcement relief, including relief for those in danger of being subjected to torture.","It applies to individuals convicted of, who admit to committing, or who admit to acts constituting the covered offenses.","Covered offenses include fraud involving SNAP benefits, Social Security benefits, or programs that receive federal funds, and the production of fraudulent identification documents."],"cboCost":{"title":"H.R. 1958, Deporting Fraudsters Act of 2026","url":"https://www.cbo.gov/publication/62101"},"latestActionDate":null,"latestActionText":null,"congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/1958"},{"bill":"H R 4638","shortTitle":"Federal Working Animal Protection Act","policyArea":"Immigration","sponsor":"Rep. Calvert, Ken [R-CA-41]","summaryBullets":["This bill establishes that a non-U.S. national convicted of, or who admits to committing, an offense related to harming animals used in law enforcement is inadmissible and deportable.","The measure was introduced as the Bill to Outlaw Wounding of Official Working Animals Act (the BOWOW Act)."],"cboCost":{"title":"H.R. 4638, Bill to Outlaw Wounding of Official Working Animals Act of 2025","url":"https://www.cbo.gov/publication/61934"},"latestActionDate":null,"latestActionText":null,"congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/4638"},{"bill":"H R 6422","shortTitle":"American Water Stewardship Act","policyArea":"Environmental Protection","sponsor":"Rep. Stauber, Pete [R-MN-8]","summaryBullets":["This bill reauthorizes several EPA water quality protection and restoration programs and adds related requirements.","Through FY2031 it reauthorizes the Great Lakes Restoration Initiative, the Long Island Sound Partnership, the Columbia River Basin Restoration Program, the National Estuary Program, and the BEACH Act program.","It modifies some programs, including designating the Mississippi Sound as an estuary of national significance under the National Estuary Program and letting BEACH Act grants be used to identify contamination sources for coastal recreation waters near public beaches.","It modifies the San Francisco Estuary Partnership to make federal agencies eligible for its grants.","It prohibits FY2026-FY2031 funding for specified Clean Water Act programs from going to nonfederal entities tied to foreign countries of concern, and directs the Government Accountability Office to evaluate and report on specified EPA geographic programs."],"cboCost":null,"latestActionDate":null,"latestActionText":null,"congressUrl":"https://www.congress.gov/bill/119th-congress/house-bill/6422"},{"bill":"H RES 1115","shortTitle":"Providing for consideration of the bill (H.R. 556) ... (H.R. 1958) ... and (H.R. 4638) ...; and relating to consideration of motions to suspend the rules.","policyArea":"Congress","sponsor":"Rep. Foxx, Virginia [R-NC-5]","summaryBullets":["This resolution sets the terms for House floor consideration of three bills: H.R. 556 (lead ammunition and tackle on federal land), H.R. 1958 (Deporting Fraudsters Act), and H.R. 4638 (harming law enforcement animals).","It also relates to consideration of motions to suspend the rules."],"cboCost":null,"latestActionDate":null,"latestActionText":null,"congressUrl":"https://www.congress.gov/bill/119th-congress/house-resolution/1115"},{"bill":"H RES 1131","shortTitle":"Providing for consideration of the bill (H.R. 8029) ... (H. Res. 1128) ... (H.R. 5103) ... and (H.R. 7084) ...; and for other purposes.","policyArea":"Congress","sponsor":"Rep. Houchin, Erin [R-IN-9]","summaryBullets":["This resolution sets the terms for House floor consideration of H.R. 8029, the FY2026 Department of Homeland Security appropriations bill.","It also provides for consideration of H. Res. 1128 (a resolution expressing support for the Department of Homeland Security), H.R. 5103 (a District of Columbia beautification program), and H.R. 7084 (a bill amending title 46 on vessels that may enter U.S. waters or transfer cargo)."],"cboCost":null,"latestActionDate":null,"latestActionText":null,"congressUrl":"https://www.congress.gov/bill/119th-congress/house-resolution/1131"},{"bill":"H J RES 139","shortTitle":"Proposing an amendment to the Constitution of the United States requiring a balanced budget for the Federal Government.","policyArea":"Economics and Public Finance","sponsor":"Rep. Biggs, Andy [R-AZ-5]","summaryBullets":["This joint resolution proposes a constitutional amendment barring total federal spending in a year from exceeding the average annual federal receipts of the prior three years, adjusted for changes in the U.S. citizen population and for inflation.","Spending to pay debt and receipts from borrowing are excluded from the calculation.","Congress could authorize spending above the limit by a two-thirds roll call vote in each chamber, or by a roll call vote in any year a declaration of war is in effect.","It also bars any bill that levies a new tax or raises a tax rate from becoming law unless approved by a two-thirds roll call vote of each chamber.","The requirements would take effect in the fifth year after the amendment is ratified."],"cboCost":null,"latestActionDate":null,"latestActionText":null,"congressUrl":"https://www.congress.gov/bill/119th-congress/house-joint-resolution/139"}];
